  Future<QuerySnapshot> getFilteredUsers() {
    return users
        .where('age', isGreaterThanOrEqualTo: 18)
        .where('age', isLessThan: 65)
        .get();
  }

  // Where with ordering
  Future<QuerySnapshot> getRecentActiveUsers() {
